
.panel,
.panel-heading,
.scene-card,
.story-grid,
.story-column {
  display: grid;
  gap: 14px;
}

.panel-heading {
  grid-template-columns: 1fr auto;
  align-items: center;
}

.panel-kicker {
  margin: 0 0 6px;
  color: var(--dnd-accent);
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.22em;
}

h2,
h3,
small {
  margin: 0;
}

.panel-actions {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

button,
input,
textarea,
select {
  border: 1px solid var(--dnd-border-soft);
  background: rgba(0, 0, 0, 0.2);
  color: var(--dnd-text);
  padding: 10px 12px;
}

label,
.story-card {
  display: grid;
  gap: 8px;
  padding: 14px;
  border: 1px solid var(--dnd-border-soft);
  background: var(--dnd-panel-soft);
}

label span {
  color: var(--dnd-text-soft);
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.14em;
}

.scene-card {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.wide {
  grid-column: 1 / -1;
}

.story-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.story-column {
  align-content: start;
}

.compact small {
  color: var(--dnd-text-soft);
}

@media (max-width: 960px) {
  .panel-heading,
  .scene-card,
  .story-grid {
    grid-template-columns: 1fr;
  }
}
