
.dashboard {
  width: min(1520px, 100%);
  margin: 0 auto;
  display: grid;
  gap: 16px;
}

.dashboard--fullscreen {
  height: 100vh;
  padding: 12px;
  grid-template-rows: auto minmax(0, 1fr);
}

.top-strip,
.top-strip__meta,
.reading-layout,
.reading-layout__left,
.reading-layout__center,
.reading-layout__right,
.summary-card,
.summary-card__header,
.character-card__stats,
.ability-grid,
.play-shell,
.play-header,
.play-body,
.transcript-entry,
.composer,
.utility-pane,
.utility-pane--overview,
.utility-modal__body,
.compact-list,
.compact-card,
.utility-modal__nav {
  display: grid;
}

.top-strip,
.summary-card,
.play-shell,
.utility-modal__panel {
  border: 1px solid var(--dnd-border);
  background:
    radial-gradient(circle at top left, rgba(215, 169, 91, 0.08), transparent 28%),
    linear-gradient(180deg, rgba(56, 40, 29, 0.9), rgba(24, 18, 14, 0.96)),
    var(--dnd-panel);
  box-shadow: var(--dnd-shadow);
}

.top-strip {
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 16px;
  align-items: center;
  padding: 18px 20px;
}

.top-strip__meta {
  grid-template-columns: minmax(0, 1fr) auto auto;
  gap: 12px;
  align-items: stretch;
  min-width: 0;
}

.top-strip__actions {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 10px;
}

.panel-kicker,
.entry-role,
.entry-state,
.composer-label,
.mini-stat span,
.chip-card span,
.ability-card span,
.copy-block span,
.compact-card__head span {
  margin: 0;
  color: var(--dnd-text-soft);
  font-size: 11px;
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.play-header h2,
.summary-card__header h2,
.transcript-entry h3,
.utility-modal__header h2 {
  margin: 0;
  font-family: var(--dnd-font-display);
}

.play-summary,
.compact-card p,
.copy-block p {
  margin: 0;
  line-height: 1.7;
  color: rgba(244, 231, 206, 0.88);
}

.mini-stat {
  display: grid;
  gap: 6px;
  align-content: center;
  min-width: 0;
}

.mini-stat--wide strong {
  display: block;
  max-width: min(36vw, 420px);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.fullscreen-button,
.utility-button,
.utility-modal__close,
.utility-modal__tab {
  border: 1px solid rgba(215, 169, 91, 0.3);
  background: rgba(255, 255, 255, 0.04);
  color: var(--dnd-text);
  padding: 10px 14px;
  cursor: pointer;
  transition:
    transform 160ms ease,
    border-color 160ms ease,
    background 160ms ease;
}

.fullscreen-button:hover,
.utility-button:hover,
.utility-modal__close:hover,
.utility-modal__tab:hover {
  transform: translateY(-1px);
  border-color: rgba(215, 169, 91, 0.55);
  background: rgba(215, 169, 91, 0.12);
}

.chip-card,
.ability-card,
.compact-card,
.copy-block {
  padding: 12px 14px;
  border: 1px solid var(--dnd-border-soft);
  background: rgba(8, 6, 5, 0.3);
}

.mini-stat strong,
.chip-card strong,
.ability-card strong,
.compact-card strong,
.character-card__meta {
  font-family: var(--dnd-font-display);
}

.reading-layout {
  grid-template-columns: minmax(280px, 0.85fr) minmax(0, 1.6fr) minmax(300px, 0.95fr);
  gap: 16px;
  align-items: start;
}

.dashboard--fullscreen .reading-layout {
  min-height: 0;
  align-items: stretch;
}

.reading-layout__left,
.reading-layout__right {
  position: sticky;
  top: 12px;
}

.dashboard--fullscreen .reading-layout__left,
.dashboard--fullscreen .reading-layout__center,
.dashboard--fullscreen .reading-layout__right {
  min-height: 0;
}

.dashboard--fullscreen .reading-layout__left,
.dashboard--fullscreen .reading-layout__right {
  top: 0;
}

.reading-layout__right {
  align-content: start;
}

.summary-card,
.play-shell {
  gap: 16px;
  padding: 18px;
}

.dashboard--fullscreen .character-card,
.dashboard--fullscreen .play-shell {
  height: 100%;
  min-height: 0;
}

.dashboard--fullscreen .character-card {
  overflow: auto;
}

.summary-card__header {
  gap: 6px;
}

.character-card__meta {
  margin: 0;
  color: var(--dnd-text-soft);
}

.hero-health {
  display: grid;
  gap: 8px;
}

.hero-health__row {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: baseline;
}

.bar {
  height: 8px;
  background: rgba(0, 0, 0, 0.22);
}

.bar i {
  display: block;
  height: 100%;
  background: linear-gradient(90deg, #cf8f46, #e9ca77);
}

.character-card__stats {
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.ability-grid {
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 10px;
}

.ability-card {
  place-items: center;
  text-align: center;
  gap: 4px;
}

.ability-card em {
  color: var(--dnd-accent);
  font-style: normal;
}

.copy-block {
  gap: 8px;
}

.play-header {
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 14px;
  align-items: start;
  padding-bottom: 14px;
  border-bottom: 1px solid rgba(215, 169, 91, 0.16);
}

.status-pill {
  padding: 8px 12px;
  border: 1px solid rgba(109, 157, 110, 0.4);
  color: #cfe8c3;
  background: rgba(72, 102, 64, 0.22);
  font-size: 12px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.status-pill--busy {
  border-color: rgba(215, 169, 91, 0.52);
  color: #f2dfb9;
  background: rgba(141, 79, 43, 0.22);
}

.play-body {
  gap: 14px;
}

.dashboard--fullscreen .play-body {
  min-height: 0;
  grid-template-rows: minmax(0, 1fr) auto;
}

.transcript {
  display: grid;
  gap: 12px;
}

.dashboard--fullscreen .transcript {
  min-height: 0;
  overflow: auto;
  padding-right: 6px;
}

.transcript-entry {
  gap: 8px;
  padding: 18px 20px;
  border-left: 3px solid rgba(215, 169, 91, 0.35);
  background: rgba(9, 7, 6, 0.3);
}

.transcript-entry--assistant {
  border-left-color: rgba(215, 169, 91, 0.92);
  background: linear-gradient(90deg, rgba(215, 169, 91, 0.08), rgba(9, 7, 6, 0.2));
}

.transcript-entry--user {
  border-left-color: rgba(110, 166, 177, 0.9);
  background: linear-gradient(90deg, rgba(110, 166, 177, 0.09), rgba(9, 7, 6, 0.2));
}

.transcript-entry--system {
  border-left-color: rgba(193, 114, 78, 0.9);
}

.entry-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  align-items: center;
}

.entry-time {
  color: var(--dnd-text-soft);
  font-size: 12px;
}

.transcript-entry p {
  margin: 0;
  line-height: 1.82;
  white-space: pre-wrap;
  word-break: break-word;
}

.composer {
  gap: 12px;
  padding: 16px;
  border: 1px solid var(--dnd-border-soft);
  background: rgba(12, 8, 7, 0.44);
}

.composer-input {
  width: 100%;
  padding: 14px 16px;
  border: 1px solid rgba(215, 169, 91, 0.28);
  resize: vertical;
  color: var(--dnd-text);
  background: rgba(5, 4, 4, 0.56);
}

.composer-input:focus {
  outline: 1px solid rgba(215, 169, 91, 0.78);
  border-color: rgba(215, 169, 91, 0.78);
}

.composer-footer {
  display: flex;
  flex-wrap: wrap;
  justify-content: space-between;
  gap: 12px;
  align-items: center;
}

.quick-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
}

.ghost-button,
.send-button {
  border: 1px solid transparent;
  padding: 10px 14px;
  cursor: pointer;
  transition:
    transform 160ms ease,
    border-color 160ms ease,
    background 160ms ease;
}

.ghost-button {
  border-color: rgba(215, 169, 91, 0.28);
  color: var(--dnd-text-soft);
  background: rgba(255, 255, 255, 0.03);
}

.send-button {
  color: #1f1510;
  font-weight: 700;
  background: linear-gradient(135deg, #f0cb84, #cc8557);
}

.ghost-button:hover,
.send-button:hover {
  transform: translateY(-1px);
}

.ghost-button:disabled,
.send-button:disabled,
.composer-input:disabled {
  cursor: not-allowed;
  opacity: 0.55;
}

.compact-list {
  gap: 10px;
}

.compact-card {
  gap: 6px;
}

.compact-card__head {
  display: flex;
  justify-content: space-between;
  gap: 12px;
  align-items: baseline;
}

.utility-modal {
  position: fixed;
  inset: 0;
  z-index: 40;
  display: grid;
  place-items: center;
  padding: 20px;
  background: rgba(4, 3, 2, 0.64);
  backdrop-filter: blur(10px);
}

.utility-modal__panel {
  width: min(1180px, 100%);
  max-height: calc(100vh - 40px);
  display: grid;
  grid-template-rows: auto auto minmax(0, 1fr);
  gap: 16px;
  padding: 20px;
}

.utility-modal__header {
  display: flex;
  justify-content: space-between;
  gap: 16px;
  align-items: start;
}

.utility-modal__nav {
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 10px;
}

.utility-modal__tab--active {
  border-color: rgba(215, 169, 91, 0.72);
  background: rgba(215, 169, 91, 0.18);
  color: #f7ddb0;
}

.utility-modal__body {
  min-height: 0;
}

.utility-pane {
  min-height: 0;
  overflow: auto;
  padding-right: 6px;
}

.utility-pane--overview {
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 16px;
}

@media (max-width: 1240px) {
  .reading-layout {
    grid-template-columns: minmax(250px, 0.8fr) minmax(0, 1.4fr);
  }

  .reading-layout__right {
    position: static;
    grid-column: 1 / -1;
  }
}

@media (max-width: 960px) {
  .top-strip,
  .reading-layout,
  .play-header,
  .composer-footer {
    grid-template-columns: 1fr;
  }

  .top-strip__meta,
  .utility-modal__nav,
  .utility-pane--overview {
    display: grid;
    grid-template-columns: 1fr;
  }

  .reading-layout__left,
  .reading-layout__right {
    position: static;
  }

  .reading-layout__center {
    order: 1;
  }

  .reading-layout__left {
    order: 2;
  }

  .reading-layout__right {
    order: 3;
  }
}

@media (max-width: 720px) {
  .summary-card,
  .play-shell,
  .top-strip,
  .utility-modal__panel {
    padding: 14px;
  }

  .character-card__stats,
  .ability-grid {
    grid-template-columns: 1fr;
  }

  .utility-button,
  .fullscreen-button,
  .utility-modal__close,
  .utility-modal__tab {
    width: 100%;
  }

  .utility-modal {
    padding: 10px;
  }
}
